#include <bits/stdc++.h>

using namespace std;

class Solution {
public:
    int* mergeSort(int* nums, int n) {
        if (n <= 1) return nums;
        int mid = n / 2;
        int* left = mergeSort(nums, mid);
        int* right = mergeSort(nums + mid, n - mid);
        return merge(left, right, n);
    }

    int* merge(int* left, int* right, int n) {
        int* result = new int[n];
        int i = 0;
        int j = 0;
        for (int k = 0; k < n; k++) {
            if (i < n && (j >= n || left[i] < right[j])) {
                result[k] = left[i];
                i++;
            } else {
                result[k] = right[j];
                j++;
            }
        }
        delete[] left;
        delete[] right;
        return result;
    }
